    parts.append(f"""WITH tm AS (SELECT m.id FROM public.modules m JOIN public.courses c ON c.id=m.course_id WHERE c.slug='power-bi-data-analyst' AND m.order_index={mi}), seed(order_index,question_type,question,options,answer,skill,explanation) AS (VALUES {','.join(vals)}) INSERT INTO public.quiz_questions(module_id,order_index,question_type,question,options,answer,difficulty,skill,explanation,is_active,is_final_test) SELECT tm.id,s.order_index,s.question_type,s.question,s.options,s.answer,CASE WHEN s.question_type='mini_challenge' THEN 'avance' WHEN s.question_type='comprehension' THEN 'intermediaire' ELSE 'debutant' END,s.skill,s.explanation,FALSE,FALSE FROM tm CROSS JOIN seed s ON CONFLICT(module_id,order_index) DO UPDATE SET question_type=EXCLUDED.question_type,question=EXCLUDED.question,options=EXCLUDED.options,answer=EXCLUDED.answer,difficulty=EXCLUDED.difficulty,skill=EXCLUDED.skill,explanation=EXCLUDED.explanation,is_active=FALSE,is_final_test=FALSE;\n""")
